# Write script to run on server
script = f"""
import json

with open('/root/books/books.json', 'r') as f:
    books = json.load(f)

new_ids = {[b['id'] for b in new_books]}
books = [b for b in books if b['id'] not in new_ids]
books.extend({json.dumps(new_books, ensure_ascii=False)})
books.sort(key=lambda x: x['id'])

with open('/root/books/books.json', 'w') as f:
    json.dump(books, f, ensure_ascii=False, indent=2)

print('Done. Total books:', len(books))
print('Added:', {[b['title'] for b in new_books]})
"""

with open('/tmp/add_books.py', 'w') as f:
    f.write(script)

print("Script ready")
